import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

/**
 * Jupiter-ring distribution:
 * Multiple orbital rings + scattered layers around the heart.
 * 50 photos fill the entire space around the heart.
 */
function getPhotoPositions(count) {
  const positions = [];

  // Ring 1: closest tight ring (like rings of Saturn/Jupiter) - 10 photos
  const ring1Count = 10;
  for (let i = 0; i < ring1Count && positions.length < count; i++) {
    const angle = (i / ring1Count) * Math.PI * 2;
    const r = 4.5 + (Math.random() - 0.5) * 0.4;
    const tilt = (Math.random() - 0.5) * 0.8;
    positions.push([
      Math.cos(angle) * r,
      tilt,
      Math.sin(angle) * r,
    ]);
  }

  // Ring 2: second orbital ring, slightly tilted - 12 photos
  const ring2Count = 12;
  const tilt2 = 0.35; // ring tilt in radians
  for (let i = 0; i < ring2Count && positions.length < count; i++) {
    const angle = (i / ring2Count) * Math.PI * 2 + 0.3;
    const r = 6.0 + (Math.random() - 0.5) * 0.5;
    positions.push([
      Math.cos(angle) * r,
      Math.sin(tilt2) * Math.sin(angle) * r * 0.4 + (Math.random() - 0.5) * 0.5,
      Math.cos(tilt2) * Math.sin(angle) * r,
    ]);
  }

  // Ring 3: outer ring, more inclined - 14 photos
  const ring3Count = 14;
  const tilt3 = -0.5;
  for (let i = 0; i < ring3Count && positions.length < count; i++) {
    const angle = (i / ring3Count) * Math.PI * 2 + 0.8;
    const r = 7.8 + (Math.random() - 0.5) * 0.6;
    positions.push([
      Math.cos(angle) * r,
      Math.sin(tilt3) * Math.cos(angle) * r * 0.3 + (Math.random() - 0.5) * 0.6,
      Math.sin(angle) * r,
    ]);
  }

  // Scattered cloud: fill remaining with spherical scatter
  while (positions.length < count) {
    const phi = Math.acos(2 * Math.random() - 1);
    const theta = Math.random() * Math.PI * 2;
    const r = 5.5 + Math.random() * 4.0;
    positions.push([
      r * Math.sin(phi) * Math.cos(theta),
      r * Math.cos(phi) * 0.5,
      r * Math.sin(phi) * Math.sin(theta),
    ]);
  }

  return positions;
}

function RealPhotoCard({ url, position, floatOffset, onClick }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);
  const texture = useTexture(url);

  useFrame((state) => {
    if (!meshRef.current) return;
    meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.55 + floatOffset) * 0.18;
    meshRef.current.rotation.y += 0.004;
    meshRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.35 + floatOffset) * 0.07;
  });

  return (
    <mesh
      ref={meshRef}
      position={[position[0], position[1], position[2]]}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.3 : 1}
    >
      <planeGeometry args={[1.3, 0.95]} />
      <meshStandardMaterial map={texture} side={THREE.FrontSide} />
    </mesh>
  );
}

function ColorCard({ color, position, floatOffset, index, onClick }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);
  const threeColor = useMemo(() => new THREE.Color(color), [color]);

  useFrame((state) => {
    if (!meshRef.current) return;
    meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.55 + floatOffset) * 0.18;
    meshRef.current.rotation.y += 0.004;
    meshRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.35 + floatOffset) * 0.07;
  });

  // Emoji icons for placeholder cards to make them look nicer
  const icons = ['💕','✨','🌹','🎂','💖','🌸','💝','🌟','💗','🥰',
                  '🎀','💞','🌺','🦋','💫','🌙','⭐','💐','🎉','🍓'];
  const icon = icons[index % icons.length];

  return (
    <mesh
      ref={meshRef}
      position={[position[0], position[1], position[2]]}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.3 : 1}
    >
      <planeGeometry args={[1.3, 0.95]} />
      <meshStandardMaterial color={threeColor} emissive={threeColor} emissiveIntensity={0.45} />
    </mesh>
  );
}

function PhotoCard({ photo, position, floatOffset, index, onClick }) {
  const isColor = photo.startsWith('__color__');
  if (isColor) {
    return <ColorCard color={photo.replace('__color__', '')} position={position} floatOffset={floatOffset} index={index} onClick={onClick} />;
  }
  return <RealPhotoCard url={photo} position={position} floatOffset={floatOffset} onClick={onClick} />;
}

export default function PhotoStars({ photos, onPhotoClick }) {
  const positions = useMemo(() => getPhotoPositions(photos.length), [photos.length]);

  return (
    <group>
      {photos.map((photo, i) => (
        <PhotoCard
          key={i}
          photo={photo}
          position={positions[i]}
          floatOffset={i * 0.63}
          index={i}
          onClick={() => onPhotoClick(photo, i)}
        />
      ))}
    </group>
  );
}
